const MAX_BATCH_IDS = 5000;

export interface VoucherBatchSelection {
  selectionMode: 'page' | 'all' | null;
  selectedIdList: string[];
}

/** Resolve ids for batch phê duyệt — hỗ trợ chọn all DB theo filter hiện tại. */
export async function resolveVoucherBatchIds<T extends { id: string }>(
  selection: VoucherBatchSelection,
  items: T[],
  isRowSelectable: (row: T) => boolean,
  fetchPage: (page: number, pageSize: number) => Promise<{ items: T[]; totalCount: number }>,
  totalCount: number,
): Promise<string[]> {
  if (selection.selectionMode === 'all') {
    const pageSize = Math.min(Math.max(totalCount, 0), MAX_BATCH_IDS);
    if (pageSize <= 0) return [];
    const res = await fetchPage(1, pageSize);
    return res.items.filter(isRowSelectable).map(r => r.id);
  }

  return selection.selectedIdList.filter(id => {
    const row = items.find(r => r.id === id);
    return row && isRowSelectable(row);
  });
}
